package httpapi

import (
	"net/http"

	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"

	"github.com/acme/api/internal/auth"
	"github.com/acme/api/internal/orders"
	"github.com/acme/api/internal/users"
)

// NewRouter builds the top-level HTTP router.
func NewRouter(deps Deps) http.Handler {
	r := chi.NewRouter()
	r.Use(middleware.RequestID)
	r.Use(middleware.RealIP)
	r.Use(middleware.Recoverer)

	// Public, unauthenticated routes.
	r.Group(func(pub chi.Router) {
		pub.Get("/healthz", healthz)
		pub.Post("/v1/auth/login", deps.Auth.LoginHandler)
	})

	// Everything else requires a verified identity.
	r.Group(func(priv chi.Router) {
		priv.Use(auth.Middleware(deps.Auth.Verifier))
		orders.Mount(priv, deps.Orders)
		users.Mount(priv, deps.Users)
	})

	return r
}

package auth

import (
	"net/http"
	"strings"
)

// Middleware returns a chi-compatible middleware that authenticates each
// request using the provided Verifier and attaches the resulting Identity to
// the request context. Requests without a valid credential get a 401.
func Middleware(v Verifier) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			header := r.Header.Get("Authorization")
			token := strings.TrimPrefix(header, "Bearer ")
			if token == header || token == "" {
				http.Error(w, "missing bearer token", http.StatusUnauthorized)
				return
			}
			id, err := v.Verify(r.Context(), token)
			if err != nil {
				http.Error(w, "invalid token", http.StatusUnauthorized)
				return
			}
			ctx := withIdentity(r.Context(), id)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

package auth

import (
	"context"
	"errors"
	"time"

	"github.com/golang-jwt/jwt/v5"
)

// Verifier turns an opaque credential string into an authenticated Identity.
// Any auth scheme (JWT, API key, mTLS) can satisfy this interface.
type Verifier interface {
	Verify(ctx context.Context, credential string) (*Identity, error)
}

// JWTVerifier verifies signed JWTs against a shared secret.
type JWTVerifier struct {
	secret []byte
}

func NewJWTVerifier(secret []byte) *JWTVerifier { return &JWTVerifier{secret: secret} }

func (j *JWTVerifier) Verify(ctx context.Context, credential string) (*Identity, error) {
	tok, err := jwt.Parse(credential, func(t *jwt.Token) (any, error) {
		return j.secret, nil
	})
	if err != nil || !tok.Valid {
		return nil, errors.New("invalid jwt")
	}
	claims := tok.Claims.(jwt.MapClaims)
	if exp, _ := claims["exp"].(float64); int64(exp) < time.Now().Unix() {
		return nil, errors.New("expired")
	}
	return &Identity{
		Subject: claims["sub"].(string),
		Scopes:  toStrings(claims["scopes"]),
		Method:  "jwt",
	}, nil
}

package auth

import "context"

// Identity is the authenticated principal for a request.
type Identity struct {
	Subject string   // stable user or service id
	Scopes  []string // granted permission scopes
	Method  string   // which scheme authenticated this request ("jwt", ...)
}

type ctxKey struct{}

func withIdentity(ctx context.Context, id *Identity) context.Context {
	return context.WithValue(ctx, ctxKey{}, id)
}

// IdentityFromContext returns the authenticated Identity, or nil if the request
// was not authenticated.
func IdentityFromContext(ctx context.Context) *Identity {
	id, _ := ctx.Value(ctxKey{}).(*Identity)
	return id
}
